function LFightReportGetter:InternalAssetLoad()
    local reportName = self._assetName
    if string.isempty(reportName) then
        self._isError = true
        self._state = _GetterState.Finished
        if LOG_INFO_ENABLED then
            printError("battlereport", "can not get reporter, assetName is null")
        end
        self:ExecuteCallback()
        return
    end
    local assetName = tostring(reportName)
    if not string.endswith(assetName, ".bytes") then
        assetName = assetName..".bytes"
    end
    local assetPath = "Report/"..assetName

    self:ClearTextAsset()

    local textAsset = require("LApp.component.res.LxTextAsset"):new(assetPath)
    self._textAsset = textAsset

    textAsset:SetLoadedCallback(function(assetObj, path)
        if self:IsDisposed() then
            return
        end

        if self._state ~= _GetterState.Requesting then
            return
        end

        if not assetObj then
            self._isError = true
            self._state = _GetterState.Finished
            if LOG_INFO_ENABLED then
                printError("battlereport", "cannot get report from asset, assetPath = "..assetPath)
            end
            self:ExecuteCallback()
            return
        end
        local data = assetObj.bytes
        self:ClearTextAsset()
        if data == "null" then
            self._isError = true
            self._state = _GetterState.Finished
            if LOG_INFO_ENABLED then
                printError("battlereport", "report data is null, assetPath = "..assetPath)
            end
            self:ExecuteCallback()
            return
        end
        self:StartParseReport(data)

    end)
    textAsset:Load()
end

