            if LOG_INFO_ENABLED then
                printError("battlereport", "cannot get report, url = "..httpUrl)
            end
            self:ExecuteCallback()
            return
        end
        if data == "null" then
            self._isError = true
            self._state = _GetterState.Finished
            if LOG_INFO_ENABLED then
                printError("battlereport", "report data is null, url = "..httpUrl)
            end
