local _field_name_set = {["rounds"] = true}
function LFightReportGetter:StartParseReport(serializedData)
    self._state = _GetterState.Parsing
    local pos = 0
    local isEnd = false
    local field_parser = nil

    local protoMsg= PJX.ProtoMessage.New()
    protoMsg:SetMessage(serializedData)

    local pb = LxProtoHelper.CreateProto(LxProtoIds.CombatReportResp)
    self._reportPb = pb
    self._frameFunc = function()
        pos, isEnd ,field_parser = pb:ParseStringByStep(protoMsg:GetMessage(), pos, field_parser,_field_name_set)
        if isEnd then
            self._frameFunc = nil
            self:OnParseFinished()
        end
    end
end

