function LFightReportGetter:ExecuteError()
    if self._errorCb then
        self._errorCb()
    end
end

function LFightReportGetter:ExecuteCallback()
    if self._isError then
        if self._cb then
            self._cb(false)
        end
        return
    end
    if self._reportData then
        --战斗状态已经销毁，不需要回调了
        if self._reportData:IsDisposed() then
            return
        end
        self._reportData:InitData(self._reportPb)
        if self._cb then
            self._cb(true,self._reportData)
        end
    else
        self._reportData = ModuleCenter.Battle:NewBattleReport(self._reportId)
        self._reportData:InitData(self._reportPb)
        if self._cb then
            self._cb(true,self._reportData)
        end
    end
end

